import { getRes } from '@meli/server-context';

import { NordicRenderingContextError } from '../../common/error';

export function validateIfHeadersSent(message: string) {
  if (!getRes().headersSent) {
    return false;
  }

  if (__DEV__) {
    throw new NordicRenderingContextError(message);
  }

  return true;
}
